CREATE DATABASE IF NOT EXISTS `monition`; USE `monition`; 
SET FOREIGN_KEY_CHECKS=0;
SET UNIQUE_CHECKS=0;
DROP TABLE IF EXISTS `decisions`;
CREATE TABLE `decisions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `takeaway_id` int NOT NULL,
  `session_id` varchar(64),
  `decided_at` datetime NOT NULL,
  `decision` enum('fire','suppress') NOT NULL,
  `evidence_count` int NOT NULL,
  `cold_start` tinyint(1) NOT NULL DEFAULT '0',
  `ev_score` decimal(5,4),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_bin;
INSERT INTO `decisions` (`id`,`takeaway_id`,`session_id`,`decided_at`,`decision`,`evidence_count`,`cold_start`,`ev_score`) VALUES (1,2,'e785c7f3-5a00-4e94-b251-16efc780bd77','2026-06-16 02:42:55','fire',0,1,NULL), (2,4,'e785c7f3-5a00-4e94-b251-16efc780bd77','2026-06-16 03:11:24','fire',0,1,NULL), (3,3,'e785c7f3-5a00-4e94-b251-16efc780bd77','2026-06-16 10:04:15','fire',0,1,NULL);
DROP TABLE IF EXISTS `firings`;
CREATE TABLE `firings` (
  `id` int NOT NULL AUTO_INCREMENT,
  `takeaway_id` int NOT NULL,
  `fired_at` datetime NOT NULL,
  `session_id` varchar(64),
  `trigger_kind` varchar(32),
  `trigger_context` varchar(512),
  `outcome` enum('helpful','noise'),
  `git_sha` varchar(40),
  `git_dirty` tinyint(1),
  `model` varchar(64),
  `monition_version` varchar(32),
  `situation` text,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_bin;
INSERT INTO `firings` (`id`,`takeaway_id`,`fired_at`,`session_id`,`trigger_kind`,`trigger_context`,`outcome`,`git_sha`,`git_dirty`,`model`,`monition_version`,`situation`) VALUES (1,2,'2026-06-16 02:42:55','e785c7f3-5a00-4e94-b251-16efc780bd77','on_demand','/goal \"Begin Fathom Phase 1 / spike M0: scaffold pyproject.toml + config.yaml + src/dh/schemas.py from \n  spike_spec.md §3; gate on test_schemas.\" And then implement that phase until complete, you run',NULL,'295d284bebb614f26c3be74c9f612fd5785ebe80',0,NULL,'0.1.0','/goal \"Begin Fathom Phase 1 / spike M0: scaffold pyproject.toml + config.yaml + src/dh/schemas.py from \n  spike_spec.md §3; gate on test_schemas.\" And then implement that phase until complete, you run out of context, or you genuinely need to ask me for somsething'), (2,4,'2026-06-16 03:11:24','e785c7f3-5a00-4e94-b251-16efc780bd77','edit_path','src/dh/environment.py',NULL,'295d284bebb614f26c3be74c9f612fd5785ebe80',1,'claude-opus-4-8','0.1.0','\"\"\"The environment interface (spec §4) — the controller\'s only window on a case.\n\nOne `Environment` ABC fronts two worlds: `LidarEnvironment` (the generated SUT, full\ndiagnostic toolset) and `BenchmarkEnvironment` (a QA passage set, `symptom`+`search`\nonly). The controller is written once against this interface and degrades gracefully\nwhen a method is unavailable (it discovers capabilities via `capabilities()` or by\ncatching `NotSupported`).\n\n**Non-negotiable #1 (ground truth is eval-only):** `LidarEnvironment` holds the `Case`\nprivately and exposes *nothing* that returns `Case.ground_truth`. The eval reads ground\ntruth from the `Case` directly; it never travels through this boundary.\n\"\"\"\n\nfrom __future__ import annotations\n\nimport re\nfrom abc import ABC, abstractmethod\n\nfrom dh import checks\nfrom dh.schemas import Artifact, Case, Node, TimeSeries\n\n_TOKEN = re.compile(r\"\\w+\")\n\n\nclass NotSupported(RuntimeError):\n    \"\"\"Raised when a method isn\'t available in this environment (e.g. lidar tools on QA).\"\"\"\n\n\ndef _tokenize(text: str) -> list[str]:\n    return _TOKEN.findall(text.lower())\n\n\ndef _in_window(ts: float | None, window: tuple[float, float] | None) -> bool:\n    if window is None:\n        return True\n    if ts is None:\n        return False\n    lo, hi = window\n    return lo <= ts <= hi\n\n\nclass Environment(ABC):\n    @abstractmethod\n    def symptom(self) -> str: ...\n\n    @abstractmethod\n    def search(self, query: str, k: int = 5) -> list[Artifact]: ...\n\n    def capabilities(self) -> set[str]:\n        \"\"\"Method names this environment supports (the controller probes this).\"\"\"\n        return {\"symptom\", \"search\"}\n\n    # --- lidar-only methods (BenchmarkEnvironment raises NotSupported) --------\n    def query_telemetry(self, signal: str, window=None, condition=None) -> TimeSeries:\n        raise NotSupported(\"query_telemetry\")\n\n    def run_check(self, name: str, args: dict) -> dict:\n        raise NotSupported(\"run_check\")\n\n    def read_logbook(self, window=None) -> list[Artifact]:\n        raise NotSupported(\"read_logbook\")\n\n    def read_errors(self, window=None) -> list[Artifact]:\n        raise NotSupported(\"read_errors\")\n\n    def read_diagnostic_actions(self) -> list[Artifact]:\n        raise NotSupported(\"read_diagnostic_actions\")\n\n    def traverse(self, node_id: str, edge_type: str, direction: str = \"out\") -> list[Node]:\n        raise NotSupported(\"traverse\")\n\n    def list_signals(self) -> list[str]:\n        raise NotSupported(\"list_signals\")\n\n\nclass LidarEnvironment(Environment):\n    \"\"\"Wraps one generated lidar `Case`. The full diagnostic toolset (spec §4).\"\"\"\n\n    _CHECKS = {\n        \"config_diff\", \"spatial_intensity_check\", \"temp_correlation_check\",\n        \"tec_load_check\", \"channel_sanity_check\", \"onset_vs_event_check\",\n    }\n\n    def __init__(self, case: Case):\n        self._case = case  # PRIVATE — ground truth must not leak past this boundary\n        self._telemetry = {s.signal: s for s in case.telemetry}\n        self._artifacts = {a.id: a for a in case.artifacts}\n        self._bm25 = None  # lazily built (rank_bm25)\n\n    # --- discovery -----------------------------------------------------------\n    def capabilities(self) -> set[str]:\n        return {\n            \"symptom\", \"search\", \"query_telemetry\", \"run_check\", \"read_logbook\",\n            \"read_errors\", \"read_diagnostic_actions\", \"traverse\", \"list_signals\",\n        }\n\n    def symptom(self) -> str:\n        for n in self._case.graph.nodes:\n            if n.type == \"KPI\" and \"symptom\" in n.props:\n                return n.props[\"symptom\"]\n        return \"A performance KPI has degraded. Diagnose the root cause.\"\n\n    # --- retrieval -----------------------------------------------------------\n    def search(self, query: str, k: int = 5) -> list[Artifact]:\n        from rank_bm25 import BM25Okapi\n\n        arts = self._case.artifacts\n        if not arts:\n            return []\n        if self._bm25 is None:\n            self._bm25 = BM25Okapi([_tokenize(f\"{a.kind} {a.text}\") fo'), (3,3,'2026-06-16 10:04:15','e785c7f3-5a00-4e94-b251-16efc780bd77','on_demand','Is this repo on github yet? If not make it a private repo.\n\ncreate a handoff file that includes a summary of all the work that needs to be done before the spike, your top 10 concerns, and relevant exe',NULL,'4bb00f505b55b3a6d08ff0a8ac5ca1437c6e412a',0,'claude-opus-4-8','0.1.0','Is this repo on github yet? If not make it a private repo.\n\ncreate a handoff file that includes a summary of all the work that needs to be done before the spike, your top 10 concerns, and relevant exercepts from tech debt or other places you think you would like a second opinion to audit. For each item leave a space for me (or another another LLM) to reply with instructions');
DROP TABLE IF EXISTS `takeaways`;
CREATE TABLE `takeaways` (
  `id` int NOT NULL AUTO_INCREMENT,
  `created` datetime NOT NULL,
  `kind` enum('gotcha','rule','preference') NOT NULL,
  `scope` varchar(255),
  `trigger_kind` enum('edit_path','session_start','on_demand') NOT NULL,
  `trigger_spec` varchar(255),
  `one_liner` varchar(500) NOT NULL,
  `full_content` text,
  `source` varchar(255),
  `status` enum('active','retired') NOT NULL DEFAULT '1',
  `mirror` enum('none','candidate','mirrored') NOT NULL DEFAULT '1',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_bin;
INSERT INTO `takeaways` (`id`,`created`,`kind`,`scope`,`trigger_kind`,`trigger_spec`,`one_liner`,`full_content`,`source`,`status`,`mirror`) VALUES (1,'2026-06-16 02:29:17','gotcha',NULL,'edit_path','.claude/*','Hook commands with relative paths (python3 tools/x.py) break when the session shell cwd drifts — anchor to $CLAUDE_PROJECT_DIR in settings.json hook commands.',NULL,NULL,'active','none'), (2,'2026-06-16 02:29:18','rule',NULL,'on_demand','handoff, resume, pick up','A handoff\'s State section is a snapshot, not ground truth — verify every \"not done yet\" claim against git log before executing; handoffs go stale within a day.',NULL,NULL,'active','none'), (3,'2026-06-16 02:29:18','gotcha',NULL,'on_demand','git --since, --until, commits since, approxidate, git log date','Computing a git log --since/--until boundary? A bare date fills its time-of-day from the current wall clock (git approxidate) — same-day commits drift in/out; pass an explicit datetime (<date> 00:00:00).','Approxidate fills a bare date\'s missing time from \"now,\" so --since <date> means \"<date> at the current time,\" not midnight. It passes unit tests written with arbitrary dates and only bites at the real same-day boundary — test there.',NULL,'active','none'), (4,'2026-06-16 02:29:18','rule',NULL,'edit_path','src/dh/controller/*, src/dh/environment.py, src/dh/baselines.py','Case.ground_truth is eval-only — it must never enter the controller\'s (or a baseline\'s) context; enforce at the environment boundary, which never exposes it.','The entire eval is invalid if ground truth leaks into reasoning. The environment is the typed boundary: it exposes symptom/search/checks/traverse but never Case.ground_truth — the controller and all baselines see only what the environment surfaces; only the eval reads ground truth. Audit any new environment method or prompt builder for accidental exposure. (spike_spec §0 item 1, §3.2; 00_README non-negotiable #1.)',NULL,'active','none'), (5,'2026-06-16 09:49:51','gotcha',NULL,'edit_path','src/dh/controller/*','Controller LLM edit: a green scripted gate != live works. The real model invents free-text ids (root_cause \'H4\' not \'part.tec\'), pollutes conflicts with junk strings, spams actions, and saturates weights. Harden deterministically AND always do a live run after the scripted gate.','test_controller_tec passes on a ScriptedBackend, which only proves loop logic (VOI, belief aggregation, stop conditions). The live CLI model drifts: root_cause came back as a hypothesis id (\'H4\') not a node id; conflicts contained \'recommend_swap_test.args.component(...)\' junk; recommend_swap_test repeated every step; evidence weights saturated BOTH the TEC hypothesis and its decoy to conf 1.0. Deterministic fixes that hold (src/dh/controller/llm.py, loop.py): _coerce_node_ref snaps node_refs to candidate ids; synthesize maps root_cause through hyp.id->node_ref; MAX_WEIGHT clamps |LLR|; the loop filters conflicts to env.node_ids() and dedups recommend_swap_test by type. The gate is necessary but not sufficient for output quality.','session 2026-06-16 / commit 8f28e5b','active','candidate'), (6,'2026-06-16 09:49:52','gotcha',NULL,'edit_path','src/dh/environment.py','BM25 search: do not gate results on score>0 -- rank_bm25 returns NEGATIVE scores on a tiny corpus (a term in every doc => negative IDF), dropping valid hits. Gate relevance on query<->doc token overlap, rank by BM25.','BM25Okapi IDF = log((N-n+0.5)/(n+0.5)); with one passage n=N=1 => log(0.5/1.5)<0, so every score is negative and a \'score>0\' filter returns nothing (the single-passage BenchmarkEnvironment search failed exactly this way). _bm25_rank now gates on set(query_tokens) & set(doc_tokens) and ranks survivors by BM25 -- robust to corpus size. Also: plain BM25 has no stemming (\'founder\' != \'founded\'); the sentence-transformers \'hybrid\' extra is the intended upgrade for corpus-volume cases.','session 2026-06-16 / commit 8f28e5b','active','candidate'), (7,'2026-06-16 09:49:52','gotcha',NULL,'edit_path','src/dh/generator/signatures.py, src/dh/generator/faults.py','Tuning one generator signal\'s noise/params shifts EVERY later signal -- the case shares one sequential RNG. Re-measure the whole case after any change, and regenerate fixtures/tec_case.json (test_generator pins it).','The generator draws all noise from one random.Random(seed) in signal-construction order, so changing intensity\'s noise reshuffles tec/power/range/region signals drawn after it. You cannot tune a single signal in isolation -- re-run the whole case and re-check the signature bands. After any intentional change, regenerate the golden fixture (command in tests/test_generator.py docstring) or test_fixture_matches_generator fails by design.','session 2026-06-16 / commit 8f28e5b','active','none');
